   /* create sample dataset */
   data orders;
     input order_id order_date : date9. order_total;
     format order_date date9.;
     datalines;
1 01jan2022 100
2 02jan2022 200
3 03jan2022 300
4 04jan2022 400
5 05jan2022 500
;
   run;

   /* use RETAIN to calculate running total and lag pattern */
   data orders_with_running_total;
     retain cumulative_total 0;
     set orders;
     /* calculate running total */
     cumulative_total + order_total;
     lag_order_total = lag(order_total);
     /* keep original variables and add new ones */
     output;
   run;

   /* print the resulting dataset */
   proc print data=orders_with_running_total;
     var order_id order_date order_total cumulative_total lag_order_total;
   run;

/* define master dataset */
data orders;
  input order_id order_date;
  datalines;
  1 20220101
  2 20220115
  3 20220201
  ;
run;

/* define transactional dataset */
data order_items;
  input order_id item_id item_name;
  datalines;
  1 101 itemA
  1 102 itemB
  2 201 itemC
  2 202 itemD
  3 301 itemE
  ;
run;

/* merge and update using MERGE_BY and MERGE_SEMANTICS */
data updated_orders;
  merge orders
        order_items(rename = (order_id = order_id_match));
  by order_id;
  if order_id = order_id_match then do;
    put 'Updating order # ' order_id;
    /* perform update logic here */
    update_order = 1;
  end;
  else do;
    put 'No match found for order # ' order_id;
    update_order = 0;
  end;
  drop order_id_match;
run;

/* print updated orders */
proc print data = updated_orders;
  var order_id order_date update_order;
run;
